mapper.select:
SELECT * FROM broker_fee_config 
WHERE account_id = #{accountId} 
AND fee_rule_type = #{feeRuleType}
AND is_active = 1
LIMIT 1

mapper.update:
UPDATE broker_fee_config
fee_rule_type = #{feeRuleType}, buy_fee_rate = #{buyFeeRate}, sell_fee_rate = #{sellFeeRate}, buy_min_fee = #{buyMinFee}, sell_min_fee = #{sellMinFee}, subscription_discount_rate = #{subscriptionDiscountRate}, is_active = #{isActive}, note = #{note}, updated_at = NOW()
WHERE id = #{id}
